
INSERT INTO public.blog_posts (title, slug, excerpt, category_id, status, published_at, author_name, reading_time_minutes, content_text, content_html) VALUES

-- Audit Preparation
('How to Prepare Your Fleet for a Successful Port State Control Audit',
 'how-to-prepare-fleet-port-state-control-audit',
 'A step-by-step guide to ensuring your vessels are audit-ready, covering documentation, crew preparedness, and common pitfalls to avoid during Port State Control inspections.',
 '3a9a8780-1edb-4569-9b87-a3a2bd357391',
 'published', now(), 'N. Shahdat', 5,
 E'## Why Audit Preparation Matters\n\nPort State Control (PSC) inspections are a reality every ship operator must face. A detention can cost tens of thousands of dollars in delays, damage your company''s reputation, and trigger concentrated inspection campaigns on your entire fleet.\n\nProper preparation is your best defence. Here is a practical framework to ensure your vessels pass with confidence.\n\n## 1. Start With Your Documentation\n\nBefore any inspector steps aboard, ensure the following are current and readily accessible:\n\n- **Statutory certificates** — SOLAS, MARPOL, Load Line, ISPS, and MLC certificates must be valid and originals kept on board.\n- **Class certificates** — Verify continuous survey status and that all conditions of class are closed.\n- **ISM documents** — The Document of Compliance (DOC) and Safety Management Certificate (SMC) must be valid, with the SMS manual reflecting actual shipboard procedures.\n\n## 2. Crew Competency and Drills\n\nInspectors frequently test crew knowledge. Officers and ratings should be able to:\n\n- Explain emergency procedures in their own words\n- Demonstrate operation of fire-fighting and life-saving equipment\n- Show familiarity with the vessel''s SMS and their specific responsibilities\n\nConduct realistic drills — not just ticking boxes — at least monthly. Record all drills with honest observations and corrective actions.\n\n## 3. Vessel Condition Walkthroughs\n\nPerform a pre-audit walkthrough covering:\n\n- **Navigation bridge** — All equipment operational, charts corrected, passage plans complete\n- **Engine room** — No visible leaks, alarm systems tested, oily water separator functioning correctly\n- **Deck and hull** — Cargo securing in order, freeing ports clear, mooring equipment maintained\n- **Accommodation** — Clean, well-lit, adequate provisions and medical supplies\n\n## 4. Address Known Deficiencies\n\nIf previous inspections flagged issues, demonstrate that corrective actions were completed. Inspectors will look at your deficiency history — a pattern of repeat findings is a red flag.\n\n## Key Takeaway\n\nAudit preparation is not a last-minute exercise. Build it into your fleet''s routine operations, and PSC inspections become a validation of good practice rather than a source of anxiety.',

 '<h2>Why Audit Preparation Matters</h2><p>Port State Control (PSC) inspections are a reality every ship operator must face. A detention can cost tens of thousands of dollars in delays, damage your company''s reputation, and trigger concentrated inspection campaigns on your entire fleet.</p><p>Proper preparation is your best defence. Here is a practical framework to ensure your vessels pass with confidence.</p><h2>1. Start With Your Documentation</h2><p>Before any inspector steps aboard, ensure the following are current and readily accessible:</p><ul><li><strong>Statutory certificates</strong> — SOLAS, MARPOL, Load Line, ISPS, and MLC certificates must be valid and originals kept on board.</li><li><strong>Class certificates</strong> — Verify continuous survey status and that all conditions of class are closed.</li><li><strong>ISM documents</strong> — The Document of Compliance (DOC) and Safety Management Certificate (SMC) must be valid, with the SMS manual reflecting actual shipboard procedures.</li></ul><h2>2. Crew Competency and Drills</h2><p>Inspectors frequently test crew knowledge. Officers and ratings should be able to:</p><ul><li>Explain emergency procedures in their own words</li><li>Demonstrate operation of fire-fighting and life-saving equipment</li><li>Show familiarity with the vessel''s SMS and their specific responsibilities</li></ul><p>Conduct realistic drills — not just ticking boxes — at least monthly. Record all drills with honest observations and corrective actions.</p><h2>3. Vessel Condition Walkthroughs</h2><p>Perform a pre-audit walkthrough covering:</p><ul><li><strong>Navigation bridge</strong> — All equipment operational, charts corrected, passage plans complete</li><li><strong>Engine room</strong> — No visible leaks, alarm systems tested, oily water separator functioning correctly</li><li><strong>Deck and hull</strong> — Cargo securing in order, freeing ports clear, mooring equipment maintained</li><li><strong>Accommodation</strong> — Clean, well-lit, adequate provisions and medical supplies</li></ul><h2>4. Address Known Deficiencies</h2><p>If previous inspections flagged issues, demonstrate that corrective actions were completed. Inspectors will look at your deficiency history — a pattern of repeat findings is a red flag.</p><h2>Key Takeaway</h2><p>Audit preparation is not a last-minute exercise. Build it into your fleet''s routine operations, and PSC inspections become a validation of good practice rather than a source of anxiety.</p>'),

-- Certification Tracking
('A Practical Guide to Managing Vessel Certification Deadlines',
 'practical-guide-managing-vessel-certification-deadlines',
 'Missing a certificate renewal can lead to detention and costly delays. Learn how to build a reliable tracking system that keeps your fleet compliant year-round.',
 'a508c336-ec3b-4082-bc70-1aa9cca95262',
 'published', now(), 'N. Shahdat', 4,
 E'## The Cost of a Missed Certificate\n\nA single expired certificate can result in vessel detention, off-hire claims, and flag state investigations. Yet many operators still rely on spreadsheets or memory to track renewal dates across a fleet. This approach fails at scale.\n\n## Building a Reliable Tracking System\n\n### Inventory Every Certificate\n\nStart by creating a complete register for each vessel. Typical certificates include:\n\n- International Tonnage Certificate\n- International Load Line Certificate\n- Safety Equipment Certificate (SEC)\n- Safety Radio Certificate (SRC)\n- Safety Construction Certificate (SCC)\n- IOPP Certificate\n- ISPS Certificate\n- Maritime Labour Certificate (MLC)\n- Document of Compliance (DOC)\n- Safety Management Certificate (SMC)\n\nFor each, record the issue date, expiry date, issuing authority, and any endorsement or annual survey windows.\n\n### Set Up Tiered Alerts\n\nA single reminder is not enough. Implement a tiered alert system:\n\n- **6 months before expiry** — Begin planning the renewal survey with your classification society\n- **3 months before expiry** — Confirm survey dates, surveyor availability, and any required dry-docking\n- **1 month before expiry** — Final verification that the renewal is in progress\n- **2 weeks before expiry** — Escalation to senior management if not yet completed\n\n### Coordinate With Class and Flag\n\nRenewal surveys often need to be harmonised with class surveys to minimise downtime. Work closely with your classification society to align survey windows and avoid conflicts with trading schedules.\n\n### Audit Your Copies\n\nEnsure that:\n\n- Original certificates are on board\n- Copies are held at the company office\n- Digital scans are stored in your document management system\n- All endorsements and amendments are attached\n\n## The DPA''s Role\n\nAs the Designated Person Ashore, certification oversight is a core responsibility. A robust tracking system protects your vessels from detention and demonstrates to auditors that your company takes compliance seriously.\n\n## Conclusion\n\nCertification management is unglamorous but essential. Invest in a proper system now, and you will avoid the operational and financial pain of an expired certificate discovery during a PSC inspection.',

 '<h2>The Cost of a Missed Certificate</h2><p>A single expired certificate can result in vessel detention, off-hire claims, and flag state investigations. Yet many operators still rely on spreadsheets or memory to track renewal dates across a fleet. This approach fails at scale.</p><h2>Building a Reliable Tracking System</h2><h3>Inventory Every Certificate</h3><p>Start by creating a complete register for each vessel. Typical certificates include:</p><ul><li>International Tonnage Certificate</li><li>International Load Line Certificate</li><li>Safety Equipment Certificate (SEC)</li><li>Safety Radio Certificate (SRC)</li><li>Safety Construction Certificate (SCC)</li><li>IOPP Certificate</li><li>ISPS Certificate</li><li>Maritime Labour Certificate (MLC)</li><li>Document of Compliance (DOC)</li><li>Safety Management Certificate (SMC)</li></ul><p>For each, record the issue date, expiry date, issuing authority, and any endorsement or annual survey windows.</p><h3>Set Up Tiered Alerts</h3><p>A single reminder is not enough. Implement a tiered alert system:</p><ul><li><strong>6 months before expiry</strong> — Begin planning the renewal survey with your classification society</li><li><strong>3 months before expiry</strong> — Confirm survey dates, surveyor availability, and any required dry-docking</li><li><strong>1 month before expiry</strong> — Final verification that the renewal is in progress</li><li><strong>2 weeks before expiry</strong> — Escalation to senior management if not yet completed</li></ul><h3>Coordinate With Class and Flag</h3><p>Renewal surveys often need to be harmonised with class surveys to minimise downtime. Work closely with your classification society to align survey windows and avoid conflicts with trading schedules.</p><h3>Audit Your Copies</h3><p>Ensure that:</p><ul><li>Original certificates are on board</li><li>Copies are held at the company office</li><li>Digital scans are stored in your document management system</li><li>All endorsements and amendments are attached</li></ul><h2>The DPA''s Role</h2><p>As the Designated Person Ashore, certification oversight is a core responsibility. A robust tracking system protects your vessels from detention and demonstrates to auditors that your company takes compliance seriously.</p><h2>Conclusion</h2><p>Certification management is unglamorous but essential. Invest in a proper system now, and you will avoid the operational and financial pain of an expired certificate discovery during a PSC inspection.</p>'),

-- SMS / ISM
('Strengthening Your Safety Management System: Key ISM Code Requirements',
 'strengthening-safety-management-system-ism-code-requirements',
 'The ISM Code is the backbone of maritime safety management. This article breaks down the key requirements and practical steps to build an SMS that works in practice, not just on paper.',
 '5ca61241-f33e-4d2d-87ad-558bcafe0952',
 'published', now(), 'N. Shahdat', 5,
 E'## Understanding the ISM Code\n\nThe International Safety Management (ISM) Code, mandated under SOLAS Chapter IX, requires every shipping company to establish a Safety Management System (SMS). But too many operators treat the SMS as a documentation exercise rather than a living operational framework.\n\n## The 13 Functional Requirements\n\nThe ISM Code sets out requirements across 13 key areas:\n\n1. **Safety and environmental protection policy** — A clear, concise policy that crew actually understand\n2. **Company responsibilities and authority** — Defined roles from shore management to the Master\n3. **Designated Person Ashore (DPA)** — Direct access to the highest level of management\n4. **Master''s responsibility and authority** — The Master''s overriding authority on safety matters\n5. **Resources and personnel** — Qualified, trained, and medically fit crew\n6. **Shipboard operations** — Procedures for key operations identified as safety-critical\n7. **Emergency preparedness** — Drills, contingency plans, and response procedures\n8. **Non-conformity reporting** — A culture that encourages reporting without blame\n9. **Maintenance** — Planned maintenance systems that actually prevent failures\n10. **Documentation** — Controlled, current, and accessible documents\n11. **Company verification and review** — Internal audits and management reviews\n12. **Certification and verification** — DOC and SMC validity\n13. **Continuous improvement** — Learning from incidents, near-misses, and audit findings\n\n## Common Weaknesses\n\nFrom my experience auditing SMS across multiple fleets, the most common weaknesses are:\n\n- **Generic procedures** copied from templates without adaptation to the vessel type or trade\n- **Poor non-conformity reporting** — crew fear reprisal, so incidents go unreported\n- **Maintenance backlogs** — planned maintenance exists on paper but is not followed in practice\n- **Lack of management review** — shore management signs off without genuinely reviewing SMS effectiveness\n\n## Practical Steps to Strengthen Your SMS\n\n### Make It Vessel-Specific\n\nAdapt every procedure to your vessel type, cargo, and trading area. A bulk carrier''s cargo operations are fundamentally different from a chemical tanker''s.\n\n### Build a Reporting Culture\n\nImplement a no-blame reporting policy and demonstrate that reports lead to genuine improvements. Share lessons learned across the fleet.\n\n### Conduct Meaningful Audits\n\nInternal audits should not be a tick-box exercise. Use experienced auditors who understand operations and can identify systemic issues.\n\n## Conclusion\n\nA strong SMS saves lives, prevents pollution, and protects your business. Invest the time to make it real.',

 '<h2>Understanding the ISM Code</h2><p>The International Safety Management (ISM) Code, mandated under SOLAS Chapter IX, requires every shipping company to establish a Safety Management System (SMS). But too many operators treat the SMS as a documentation exercise rather than a living operational framework.</p><h2>The 13 Functional Requirements</h2><p>The ISM Code sets out requirements across 13 key areas:</p><ol><li><strong>Safety and environmental protection policy</strong> — A clear, concise policy that crew actually understand</li><li><strong>Company responsibilities and authority</strong> — Defined roles from shore management to the Master</li><li><strong>Designated Person Ashore (DPA)</strong> — Direct access to the highest level of management</li><li><strong>Master''s responsibility and authority</strong> — The Master''s overriding authority on safety matters</li><li><strong>Resources and personnel</strong> — Qualified, trained, and medically fit crew</li><li><strong>Shipboard operations</strong> — Procedures for key operations identified as safety-critical</li><li><strong>Emergency preparedness</strong> — Drills, contingency plans, and response procedures</li><li><strong>Non-conformity reporting</strong> — A culture that encourages reporting without blame</li><li><strong>Maintenance</strong> — Planned maintenance systems that actually prevent failures</li><li><strong>Documentation</strong> — Controlled, current, and accessible documents</li><li><strong>Company verification and review</strong> — Internal audits and management reviews</li><li><strong>Certification and verification</strong> — DOC and SMC validity</li><li><strong>Continuous improvement</strong> — Learning from incidents, near-misses, and audit findings</li></ol><h2>Common Weaknesses</h2><p>From my experience auditing SMS across multiple fleets, the most common weaknesses are:</p><ul><li><strong>Generic procedures</strong> copied from templates without adaptation to the vessel type or trade</li><li><strong>Poor non-conformity reporting</strong> — crew fear reprisal, so incidents go unreported</li><li><strong>Maintenance backlogs</strong> — planned maintenance exists on paper but is not followed in practice</li><li><strong>Lack of management review</strong> — shore management signs off without genuinely reviewing SMS effectiveness</li></ul><h2>Practical Steps to Strengthen Your SMS</h2><h3>Make It Vessel-Specific</h3><p>Adapt every procedure to your vessel type, cargo, and trading area. A bulk carrier''s cargo operations are fundamentally different from a chemical tanker''s.</p><h3>Build a Reporting Culture</h3><p>Implement a no-blame reporting policy and demonstrate that reports lead to genuine improvements. Share lessons learned across the fleet.</p><h3>Conduct Meaningful Audits</h3><p>Internal audits should not be a tick-box exercise. Use experienced auditors who understand operations and can identify systemic issues.</p><h2>Conclusion</h2><p>A strong SMS saves lives, prevents pollution, and protects your business. Invest the time to make it real.</p>'),

-- Operational Compliance
('Navigating MARPOL Annex VI: Emission Compliance for Ship Operators',
 'navigating-marpol-annex-vi-emission-compliance-ship-operators',
 'With tightening emission regulations under MARPOL Annex VI, ship operators must stay ahead of compliance requirements. This guide covers sulphur cap enforcement, EEXI, CII, and practical compliance strategies.',
 'b76f572f-ddb8-4cc0-b29f-f34dff1cfeb3',
 'published', now(), 'N. Shahdat', 5,
 E'## The Evolving Emission Landscape\n\nMARPOL Annex VI has fundamentally changed how ships operate. From the global 0.50% sulphur cap to the Carbon Intensity Indicator (CII), operators face an increasingly complex regulatory environment.\n\n## Key Compliance Areas\n\n### Sulphur Cap (Regulation 14)\n\nSince 1 January 2020, all vessels must use fuel with a sulphur content not exceeding 0.50% m/m globally, or 0.10% in Emission Control Areas (ECAs). Compliance options include:\n\n- **Low-sulphur fuel oil (VLSFO)** — The most common approach, but requires careful fuel management\n- **Exhaust gas cleaning systems (scrubbers)** — Allows continued use of HFO but requires ongoing maintenance and monitoring\n- **LNG or alternative fuels** — The long-term solution but requires significant capital investment\n\n### Energy Efficiency Existing Ship Index (EEXI)\n\nSince 1 January 2023, all existing ships must meet an EEXI requirement. Ships that exceed the threshold must implement technical measures such as:\n\n- Engine power limitation (EPL)\n- Shaft generator installation\n- Energy-saving devices (propeller ducts, bulbous bow optimisation)\n\n### Carbon Intensity Indicator (CII)\n\nThe CII rates vessels annually from A to E based on their operational carbon intensity. Ships rated D for three consecutive years, or E in any year, must submit a corrective action plan. Practical measures include:\n\n- Speed optimisation and slow steaming\n- Weather routing\n- Hull and propeller cleaning schedules\n- Port turnaround efficiency improvements\n\n## Documentation Requirements\n\nOperators must maintain:\n\n- **International Energy Efficiency Certificate (IEEC)** with EEXI technical file\n- **Ship Energy Efficiency Management Plan (SEEMP) Part III** with CII implementation plan\n- **Fuel Oil Delivery Notes (BDNs)** retained for three years\n- **Oil Record Book** with accurate entries for all fuel operations\n\n## Enforcement and Penalties\n\nPSC officers are increasingly trained to verify emission compliance. Common inspection points include:\n\n- Fuel samples and BDN cross-checking\n- Scrubber discharge water monitoring records\n- SEEMP and CII documentation review\n\n## Practical Advice\n\nStart with what you can control: optimise speed, maintain hull cleanliness, and ensure accurate data reporting. These operational measures often deliver the most cost-effective CII improvements.',

 '<h2>The Evolving Emission Landscape</h2><p>MARPOL Annex VI has fundamentally changed how ships operate. From the global 0.50% sulphur cap to the Carbon Intensity Indicator (CII), operators face an increasingly complex regulatory environment.</p><h2>Key Compliance Areas</h2><h3>Sulphur Cap (Regulation 14)</h3><p>Since 1 January 2020, all vessels must use fuel with a sulphur content not exceeding 0.50% m/m globally, or 0.10% in Emission Control Areas (ECAs). Compliance options include:</p><ul><li><strong>Low-sulphur fuel oil (VLSFO)</strong> — The most common approach, but requires careful fuel management</li><li><strong>Exhaust gas cleaning systems (scrubbers)</strong> — Allows continued use of HFO but requires ongoing maintenance and monitoring</li><li><strong>LNG or alternative fuels</strong> — The long-term solution but requires significant capital investment</li></ul><h3>Energy Efficiency Existing Ship Index (EEXI)</h3><p>Since 1 January 2023, all existing ships must meet an EEXI requirement. Ships that exceed the threshold must implement technical measures such as:</p><ul><li>Engine power limitation (EPL)</li><li>Shaft generator installation</li><li>Energy-saving devices (propeller ducts, bulbous bow optimisation)</li></ul><h3>Carbon Intensity Indicator (CII)</h3><p>The CII rates vessels annually from A to E based on their operational carbon intensity. Ships rated D for three consecutive years, or E in any year, must submit a corrective action plan. Practical measures include:</p><ul><li>Speed optimisation and slow steaming</li><li>Weather routing</li><li>Hull and propeller cleaning schedules</li><li>Port turnaround efficiency improvements</li></ul><h2>Documentation Requirements</h2><p>Operators must maintain:</p><ul><li><strong>International Energy Efficiency Certificate (IEEC)</strong> with EEXI technical file</li><li><strong>Ship Energy Efficiency Management Plan (SEEMP) Part III</strong> with CII implementation plan</li><li><strong>Fuel Oil Delivery Notes (BDNs)</strong> retained for three years</li><li><strong>Oil Record Book</strong> with accurate entries for all fuel operations</li></ul><h2>Enforcement and Penalties</h2><p>PSC officers are increasingly trained to verify emission compliance. Common inspection points include:</p><ul><li>Fuel samples and BDN cross-checking</li><li>Scrubber discharge water monitoring records</li><li>SEEMP and CII documentation review</li></ul><h2>Practical Advice</h2><p>Start with what you can control: optimise speed, maintain hull cleanliness, and ensure accurate data reporting. These operational measures often deliver the most cost-effective CII improvements.</p>'),

-- PSC Inspection
('Common PSC Deficiencies and How to Avoid Them',
 'common-psc-deficiencies-how-to-avoid-them',
 'An analysis of the most frequently cited PSC deficiencies worldwide, with actionable advice on how to prevent them and protect your fleet from detention.',
 '2bbcaa2f-e207-4543-bd9c-c8875fc2dfa4',
 'published', now(), 'N. Shahdat', 4,
 E'## Understanding PSC Deficiency Trends\n\nEvery year, Port State Control regimes publish statistics on the most common deficiencies found during inspections. Understanding these trends helps you focus your preparation efforts where they matter most.\n\n## Top Deficiency Categories\n\nBased on data from major MoU regimes (Paris, Tokyo, Indian Ocean), the most frequently cited deficiency areas consistently include:\n\n### 1. Fire Safety\n\nFire safety deficiencies account for the largest share of findings globally. Common issues:\n\n- **Fire doors** not self-closing or with damaged seals\n- **Fire dampers** seized or not tested regularly\n- **Fire extinguishers** overdue for inspection or service\n- **Fire detection systems** with isolated or bypassed zones\n- **Fire hoses and nozzles** in poor condition\n\n**Prevention:** Conduct monthly fire safety rounds with a detailed checklist. Test all fire doors, dampers, and detection zones quarterly.\n\n### 2. Life-Saving Appliances\n\nDeficiencies in life-saving appliances are a leading cause of detentions:\n\n- **Lifeboat launching gear** not properly maintained or tested\n- **Liferaft hydrostatic releases** expired\n- **Immersion suits** damaged or missing\n- **EPIRB and SART** batteries expired or not registered\n\n**Prevention:** Follow the manufacturer''s maintenance schedule rigorously. Keep a spare parts inventory for critical items.\n\n### 3. Navigation Safety\n\n- **ECDIS** software not updated or crew not trained\n- **Passage plans** incomplete or not covering berth-to-berth\n- **Navigation lights** defective\n- **Bridge equipment** (radar, AIS, echo sounder) not functioning properly\n\n**Prevention:** Verify all navigation equipment before departure. Ensure passage plans are comprehensive and signed off by the Master.\n\n### 4. ISM-Related Findings\n\n- Crew unable to explain emergency procedures\n- Drill records incomplete or unrealistic\n- Non-conformity reports not properly closed out\n- Master''s review not conducted\n\n**Prevention:** Focus on crew competence, not just paperwork. The SMS should be a tool that crew use, not a binder they have never opened.\n\n### 5. MARPOL-Related\n\n- Oil Record Book entries incorrect or missing\n- Oily water separator malfunctioning\n- Garbage management plan not followed\n- Sewage treatment plant deficiencies\n\n**Prevention:** Train officers on accurate record-keeping. Verify OWS functionality regularly through actual testing.\n\n## The Detention Threshold\n\nNot every deficiency leads to detention. Inspectors exercise professional judgement and consider whether the deficiency poses a genuine risk to safety, health, or the environment. However, multiple minor deficiencies can collectively indicate a systemic problem that warrants detention.\n\n## Conclusion\n\nThe best defence against PSC deficiencies is a proactive maintenance culture combined with genuine crew competence. Focus on the top five categories above, and you will significantly reduce your detention risk.',

 '<h2>Understanding PSC Deficiency Trends</h2><p>Every year, Port State Control regimes publish statistics on the most common deficiencies found during inspections. Understanding these trends helps you focus your preparation efforts where they matter most.</p><h2>Top Deficiency Categories</h2><p>Based on data from major MoU regimes (Paris, Tokyo, Indian Ocean), the most frequently cited deficiency areas consistently include:</p><h3>1. Fire Safety</h3><p>Fire safety deficiencies account for the largest share of findings globally. Common issues:</p><ul><li><strong>Fire doors</strong> not self-closing or with damaged seals</li><li><strong>Fire dampers</strong> seized or not tested regularly</li><li><strong>Fire extinguishers</strong> overdue for inspection or service</li><li><strong>Fire detection systems</strong> with isolated or bypassed zones</li><li><strong>Fire hoses and nozzles</strong> in poor condition</li></ul><p><strong>Prevention:</strong> Conduct monthly fire safety rounds with a detailed checklist. Test all fire doors, dampers, and detection zones quarterly.</p><h3>2. Life-Saving Appliances</h3><p>Deficiencies in life-saving appliances are a leading cause of detentions:</p><ul><li><strong>Lifeboat launching gear</strong> not properly maintained or tested</li><li><strong>Liferaft hydrostatic releases</strong> expired</li><li><strong>Immersion suits</strong> damaged or missing</li><li><strong>EPIRB and SART</strong> batteries expired or not registered</li></ul><p><strong>Prevention:</strong> Follow the manufacturer''s maintenance schedule rigorously. Keep a spare parts inventory for critical items.</p><h3>3. Navigation Safety</h3><ul><li><strong>ECDIS</strong> software not updated or crew not trained</li><li><strong>Passage plans</strong> incomplete or not covering berth-to-berth</li><li><strong>Navigation lights</strong> defective</li><li><strong>Bridge equipment</strong> (radar, AIS, echo sounder) not functioning properly</li></ul><p><strong>Prevention:</strong> Verify all navigation equipment before departure. Ensure passage plans are comprehensive and signed off by the Master.</p><h3>4. ISM-Related Findings</h3><ul><li>Crew unable to explain emergency procedures</li><li>Drill records incomplete or unrealistic</li><li>Non-conformity reports not properly closed out</li><li>Master''s review not conducted</li></ul><p><strong>Prevention:</strong> Focus on crew competence, not just paperwork. The SMS should be a tool that crew use, not a binder they have never opened.</p><h3>5. MARPOL-Related</h3><ul><li>Oil Record Book entries incorrect or missing</li><li>Oily water separator malfunctioning</li><li>Garbage management plan not followed</li><li>Sewage treatment plant deficiencies</li></ul><p><strong>Prevention:</strong> Train officers on accurate record-keeping. Verify OWS functionality regularly through actual testing.</p><h2>The Detention Threshold</h2><p>Not every deficiency leads to detention. Inspectors exercise professional judgement and consider whether the deficiency poses a genuine risk to safety, health, or the environment. However, multiple minor deficiencies can collectively indicate a systemic problem that warrants detention.</p><h2>Conclusion</h2><p>The best defence against PSC deficiencies is a proactive maintenance culture combined with genuine crew competence. Focus on the top five categories above, and you will significantly reduce your detention risk.</p>');
